 1	import * as React from 'react';
 2	import {
 3	  Button,
 4	  ButtonType,
 5	  ButtonVariant,
 6	  Tooltip,
 7	} from '@patternfly/react-core';
 8	import { MinusCircleIcon } from '@patternfly/react-icons';
 9	import { useField } from 'formik';
10	import { Trans, useTranslation } from 'react-i18next';
11	import MultiColumnField from '../../pipelines-details/multi-column-field/MultiColumnField';
12	import { SelectedBuilderTask } from '../../../types';
13	import { useBuilderParams } from '../../auto-complete/autoCompleteValueParsers';
14	import { RowRendererProps } from '../../pipelines-details/multi-column-field/types';
15	import WhenExpressionForm from '../WhenExpressionForm';
16	
17	import './TaskSidebarWhenExpression.scss';
18	
19	type TaskSidebarWhenExpressionProps = {
20	  hasParam: boolean;
21	  name: string;
22	  selectedData: SelectedBuilderTask;
23	};
24	
25	const TaskSidebarWhenExpression: React.FC<TaskSidebarWhenExpressionProps> = (
26	  props,
27	) => {
28	  const { name, selectedData } = props;
29	  const [field] = useField(name);
30	  const { t } = useTranslation('plugin__pipelines-console-plugin');
31	  const removeWhenExpressionLabel = t('Remove when expression');
32	  const autoCompleteValues: string[] = useBuilderParams(selectedData);
33	
34	  return (
35	    <div className="opp-task-sidebar-when-expression">
36	      <h2>{t('When expressions')}</h2>
37	      <p className="co-help-text opp-task-sidebar__paragraph">
38	        {field.value?.length > 0 ? (
39	          <Trans ns="plugin__pipelines-console-plugin">
40	            Use this format when you reference variables in this form:{' '}
41	            <code className="co-code">$(</code>
42	          </Trans>
43	        ) : (
44	          t('No when expressions are associated with this task.')
45	        )}
46	      </p>
47	      <MultiColumnField
48	        data-test="when-expression"
49	        name={name}
50	        addLabel={t('Add when expression')}
51	        headers={[]}
52	        emptyValues={{ input: '', operator: '', values: [''] }}
53	        rowRenderer={({ onDelete, fieldName }: RowRendererProps) => (
54	          <div
55	            className="opp-task-sidebar-when-expression__section"
56	            data-test={`row ${fieldName}`}
57	          >
58	            <WhenExpressionForm
59	              autoCompleteValues={autoCompleteValues}
60	              namePrefix={fieldName}
61	            />
62	            <div className="opp-task-sidebar-when-expression__control-button-wrapper">
63	              <Tooltip content={removeWhenExpressionLabel}>
64	                <Button
65	                  onClick={onDelete}
66	                  data-test="remove-when-expression"
67	                  className="opp-task-sidebar-when-expression__control-button"
68	                  aria-label={removeWhenExpressionLabel}
69	                  variant={ButtonVariant.plain}
70	                  type={ButtonType.button}
71	                >
72	                  <MinusCircleIcon />
73	                  <span className="opp-task-sidebar-when-expression__control-label">
74	                    {removeWhenExpressionLabel}
75	                  </span>
76	                </Button>
77	              </Tooltip>
78	            </div>
79	          </div>
80	        )}
81	      />
82	    </div>
83	  );
84	};
85	
86	export default TaskSidebarWhenExpression;

